input.content:
type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const itemBase = (item: Item): number => {
  return BASE_PREMIUM[item.type] ?? 0;
};

const itemPremium = (item: Item): number => {
  const base = itemBase(item);
  // First insurance applies to each item
  return base + base * 0.1;
};

const quotePremium = (items: Item[]): number => {
  const sum = items.reduce((acc, it) => acc + itemPremium(it), 0);
  return Math.ceil(sum + 5);
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

