import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Quote: base premiums ---
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote a single plain sword yields 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    // Newcomer first insurance: 100 + 10 (first insurance) + 5 fee = 115. Wait - check
    // Actually with 0 years and first quote, "first insurance" applies, no follow-up.
    // 100 base + 10 first insurance = 110 + 5 fee = 115.
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote a single plain amulet yields 71 G (60 + 6 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote a single plain staff yields 93 G (80 + 8 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote a single plain potion yields 49 G (40 + 4 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });
  it("quote two plain swords: 200 + 20 first ins + 5 fee = 225 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 225 }] });
  });
  it("quote a sword and an amulet: 100 + 60 + 16 first ins + 5 fee = 181 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 181 }] });
  });

  // --- Components and blocks ---
  it("quote 1 rune: 25 + 2.5 first ins + 5 fee, rounded up = 33 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it.todo("quote 2 runes yields 55 G (50 + 5)");
  it.todo("quote 3 runes uses block discount and yields 65 G (60 + 5)");
  it.todo("quote 4 runes yields 105 G (100 + 5, no block)");
  it.todo("quote 7 runes yields 180 G (175 + 5, no block)");
  it.todo("quote 2 runes + 1 moonstone yields 80 G (75 + 5, no block)");
  it.todo("quote 3 runes + 3 moonstones yields 125 G (120 + 5, two blocks)");

  // --- Item-level modifiers ---
  it.todo("cursed sword adds 50% surcharge on that item base");
  it.todo("high enchantment (>=5) adds 30% surcharge on that item base");
  it.todo("cursed sword with enchantment 5 adds both surcharges");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("cursed sword + plain amulet: curse applies only to sword base");

  // --- Policy-level modifiers ---
  it.todo("loyalty discount applies at exactly 2 years with MHPCO");
  it.todo("first insurance adds 10% surcharge for the first quote");
  it.todo("follow-up contract receives 15% discount on subsequent quotes");
  it.todo("processing fee is added at the very end");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword yields 165 G");
  it.todo("long-standing customer second contract with cursed enchanted sword yields 160 G");

  // --- Rounding ---
  it.todo("premium rounds up in MHPCO's favor (197.5 -> 198)");

  // --- Claim: basics ---
  it.todo("claim with no special clauses pays damage minus 100 deductible");
  it.todo("claim on a rune (no enchantment/material) applies only deductible");
  it.todo("claim where damage <= deductible pays 0");

  // --- Claim: special clauses ---
  it.todo("damage on item with enchantment >= 8 reimbursed at 50% then deductible");
  it.todo("damage on dragon-material item fully reimbursed then deductible");
  it.todo("dragon-material + enchantment >= 8: 50% rule wins then deductible");
  it.todo("dragon-material + enchantment 5: full reimbursement then deductible");

  // --- Claim: multiple damages and deductibles ---
  it.todo("multi-item damage applies deductible per damage event");
  it.todo("multiple same-type items: each damage entry is separate");

  // --- Claim: caps ---
  it.todo("policy cap is twice the insurance sum");
  it.todo("cap is based on unmodified insurance values");
  it.todo("successive claims deplete remaining cap");
  it.todo("block discount does not affect insurance sum (cap)");

  // --- Claim: payout rounding ---
  it.todo("payout rounds down in MHPCO's favor (350.5 -> 350)");

  // --- Error handling ---
  it.todo("quote with unknown item type exits non-zero with stderr message");
  it.todo("claim referencing item not in policy exits non-zero");
  it.todo("claim with negative damage amount exits non-zero");
  it.todo("claim with more damages of a type than insured exits non-zero");
});

