type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

const MAIN_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BASE = 25;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const mainItemPremium = (item: Item): number => {
  const base = MAIN_BASE_PREMIUM[item.type] ?? 0;
  let total = base;
  if (item.cursed) total += base * 0.5;
  if ((item.enchantment ?? 0) >= 5) total += base * 0.3;
  total += base * 0.1; // first insurance
  return total;
};

const componentsPremium = (components: Item[]): number => {
  // group by type
  const counts = new Map<string, number>();
  for (const c of components) {
    counts.set(c.type, (counts.get(c.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of counts.values()) {
    // each block of exactly 3 alike: 60, else 25 per. Block only triggers on exactly 3.
    if (count === 3) total += 60;
    else total += count * COMPONENT_BASE;
  }
  // first insurance applies to the component base sum
  return total + total * 0.1;
};

const quotePremium = (items: Item[]): number => {
  const mainItems = items.filter((i) => !isComponent(i));
  const components = items.filter(isComponent);
  const mainSum = mainItems.reduce((acc, it) => acc + mainItemPremium(it), 0);
  const compSum = componentsPremium(components);
  return Math.ceil(mainSum + compSum + 5);
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

