    expect(result).toEqual({ results: [{ premium: 231 }] });
  });

  // --- Policy-level modifiers ---
  it.todo("loyalty discount applies at exactly 2 years with MHPCO");
  it.todo("first insurance adds 10% surcharge for the first quote");
  it.todo("follow-up contract receives 15% discount on subsequent quotes");
  it.todo("processing fee is added at the very end");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword yields 165 G");
  it.todo("long-standing customer second contract with cursed enchanted sword yields 160 G");

  // --- Rounding ---
